import { scryptSync, randomBytes, timingSafeEqual, createHmac } from 'crypto';

const TOKEN_SECRET = process.env.TOKEN_SECRET || process.env.SUPABASE_SERVICE_ROLE_KEY;
const KEY_LENGTH = 64;

export async function hashPassword(password: string): Promise<string> {
  const salt = randomBytes(32).toString('hex');
  const derivedKey = scryptSync(password, salt, KEY_LENGTH) as Buffer;
  return salt + ':' + derivedKey.toString('hex');
}

export async function verifyPassword(password: string, hash: string): Promise<boolean> {
  const parts = hash.split(':');
  if (parts.length !== 2) return false;
  const [salt, key] = parts;
  const derivedKey = scryptSync(password, salt, KEY_LENGTH) as Buffer;
  const keyBuffer = Buffer.from(key, 'hex');
  if (derivedKey.length !== keyBuffer.length) return false;
  try {
    return timingSafeEqual(derivedKey, keyBuffer);
  } catch {
    return false;
  }
}

export function createToken(userId: string, role: string): string {
  const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'JWT' })).toString('base64url');
  const now = Math.floor(Date.now() / 1000);
  const payload = Buffer.from(
    JSON.stringify({
      sub: userId,
      role,
      iat: now,
      exp: now + 86400 * 7,
    })
  ).toString('base64url');
  const signature = createHmac('sha256', TOKEN_SECRET || 'fallback')
    .update(`${header}.${payload}`)
    .digest('base64url');
  return `${header}.${payload}.${signature}`;
}

export function verifyToken(token: string): { userId: string; role: string } | null {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;
    const [header, payload, signature] = parts;

    const expectedSig = createHmac('sha256', TOKEN_SECRET || 'fallback')
      .update(`${header}.${payload}`)
      .digest('base64url');

    const sigBuffer = Buffer.from(signature, 'base64url');
    const expectedBuffer = Buffer.from(expectedSig, 'base64url');
    if (
      sigBuffer.length !== expectedBuffer.length ||
      !timingSafeEqual(sigBuffer, expectedBuffer)
    ) {
      return null;
    }

    const data = JSON.parse(Buffer.from(payload, 'base64url').toString());
    if (data.exp && data.exp < Math.floor(Date.now() / 1000)) return null;

    return { userId: data.sub, role: data.role };
  } catch {
    return null;
  }
}

export function getCompanyContext(
  request: Request
): { companyId: string; userId: string; role: string } | null {
  try {
    const authHeader = request.headers.get('authorization') || '';
    const token = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : '';

    const companyId =
      request.headers.get('x-company-id') ||
      request.headers.get('x-company') ||
      '';

    if (!token || !companyId) return null;

    const payload = verifyToken(token);
    if (!payload) return null;

    return {
      companyId,
      userId: payload.userId,
      role: payload.role,
    };
  } catch {
    return null;
  }
}

import { NextRequest } from 'next/server';
import { verifyToken } from '@/lib/auth';
import { query } from '@/lib/db';
import { verifyPassword } from '@/lib/auth';

export interface AdminPayload {
  userId: string;
  role: string;
}

export async function verifyAdminToken(request: NextRequest): Promise<AdminPayload | null> {
  const token = request.cookies.get('admin_token')?.value;
  if (!token) return null;
  const payload = verifyToken(token);
  if (!payload || payload.role !== 'superadmin') return null;
  return payload;
}

export async function verifyMasterPassword(adminId: string, masterPassword: string): Promise<boolean> {
  const res = await query(
    `SELECT master_password_hash FROM admin_users WHERE id = $1`,
    [adminId]
  );
  if (res.rows.length === 0) return false;
  return verifyPassword(masterPassword, res.rows[0].master_password_hash);
}

export async function auditLog(
  adminId: string,
  action: string,
  details?: string,
  targetType?: string,
  targetId?: string
): Promise<void> {
  await query(
    `INSERT INTO admin_audit_log (admin_id, action, details, target_type, target_id)
     VALUES ($1, $2, $3, $4, $5)`,
    [adminId, action, details || null, targetType || null, targetId || null]
  );
}

interface AdminSessionData {
  email: string;
  code: string;
  step: 'code_sent' | 'telegram_verified';
  codeSent: boolean;
  expiresAt: number;
}

const store = new Map<string, AdminSessionData>();
const TTL = 30 * 60 * 1000;

export function createAdminSession(sessionId: string, email: string, code: string): AdminSessionData {
  const data = { email, code, step: 'code_sent' as const, codeSent: false, expiresAt: Date.now() + TTL };
  store.set(sessionId, data);
  return data;
}

export function getAdminSession(sessionId: string): AdminSessionData | undefined {
  const s = store.get(sessionId);
  if (!s) return undefined;
  if (Date.now() > s.expiresAt) {
    store.delete(sessionId);
    return undefined;
  }
  return s;
}

export function updateAdminSession(sessionId: string, updates: Partial<Pick<AdminSessionData, 'step' | 'codeSent'>>): void {
  const s = store.get(sessionId);
  if (s) Object.assign(s, updates);
}

export function deleteAdminSession(sessionId: string): void {
  store.delete(sessionId);
}

import { NextResponse } from 'next/server';

export function success<T>(data: T, status = 200) {
  return NextResponse.json({ success: true, data }, { status });
}

export function error(message: string, status = 400) {
  return NextResponse.json({ success: false, message }, { status });
}

export function unauthorized() {
  return error('Unauthorized', 401);
}

export function notFound() {
  return error('Not found', 404);
}

export function validationError(errors: Record<string, string[]> | string) {
  return NextResponse.json({ success: false, message: 'Validation failed', errors }, { status: 422 });
}

export function serverError(err: unknown) {
  console.error('Server error:', err);
  return NextResponse.json({ success: false, message: 'Internal server error' }, { status: 500 });
}

export async function parseBody<T = any>(request: Request): Promise<T> {
  return request.json();
}

export function getPaginationParams(url: string | URL): { page: number; pageSize: number } {
  const urlObj = url instanceof URL ? url : new URL(url, 'http://localhost');
  const page = Math.max(1, parseInt(urlObj.searchParams.get('page') || '1', 10) || 1);
  const pageSize = Math.min(500, Math.max(1, parseInt(urlObj.searchParams.get('pageSize') || '50', 10) || 50));
  return { page, pageSize };
}

export function getDateRangeParams(url: string | URL): { from: string | null; to: string | null } {
  const urlObj = url instanceof URL ? url : new URL(url, 'http://localhost');
  const from = urlObj.searchParams.get('from') || null;
  const to = urlObj.searchParams.get('to') || null;
  return { from, to };
}

