import { NextRequest } from 'next/server';
import { success, error, unauthorized, serverError, parseBody } from '@/lib/api-helpers';
import { query } from '@/lib/db';
import { verifyPassword, createToken } from '@/lib/auth';
import { loginSchema } from '@/lib/validation';

export async function POST(request: NextRequest) {
  try {
    const body = await parseBody<{ email: string; password: string }>(request);
    const parsed = loginSchema.safeParse(body);
    if (!parsed.success) {
      return error(parsed.error.issues[0].message);
    }

    const { email, password } = parsed.data;

    const res = await query(
      `SELECT u.id, u.name, u.email, u.password, u.role, u.is_active, u.company_id,
              c.name as company_name, c.registration_number, c.tax_number,
              c.vat_number, c.address, c.phone, c.email as company_email,
              c.logo, c.is_active as company_active
       FROM users u
       JOIN companies c ON c.id = u.company_id
       WHERE u.email = LOWER($1)`,
      [email]
    );

    if (res.rows.length === 0) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const user = res.rows[0];

    if (!user.is_active) {
      return error('هذا الحساب غير نشط. تواصل مع مدير النظام', 403);
    }

    if (!user.company_active) {
      return error('الشركة غير نشطة. تواصل مع مدير النظام', 403);
    }

    const valid = await verifyPassword(password, user.password);
    if (!valid) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const token = createToken(user.id, user.role);

    await query(
      `UPDATE users SET last_login = NOW()::timestamp WHERE id = $1`,
      [user.id]
    );

    const { password: _, ...safeUser } = user;

    const response = success({
      user: safeUser,
      company: {
        id: user.company_id,
        name: user.company_name,
        registrationNumber: user.registration_number,
        taxNumber: user.tax_number,
        vatNumber: user.vat_number,
        address: user.address,
        phone: user.phone,
        email: user.company_email,
        logo: user.logo,
      },
      token,
    });

    response.cookies.set('token', token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: 86400 * 7,
      path: '/',
    });

    return response;
  } catch (err) {
    return serverError(err);
  }
}

import { NextRequest } from 'next/server';
import { success, error, serverError, parseBody } from '@/lib/api-helpers';
import { query } from '@/lib/db';
import { verifyPassword } from '@/lib/auth';
import { adminLoginSchema } from '@/lib/validation';
import { sendTelegramCode } from '@/lib/telegram';
import { generateId } from '@/lib/utils';
import { createAdminSession, updateAdminSession } from '@/lib/admin-session';

export async function POST(request: NextRequest) {
  try {
    const body = await parseBody<{ email: string; password: string }>(request);
    const parsed = adminLoginSchema.safeParse(body);
    if (!parsed.success) {
      return error('البريد الإلكتروني أو كلمة المرور غير صالحة');
    }

    const { email, password } = parsed.data;

    const res = await query(
      `SELECT id, name, email, password_hash, is_active
       FROM admin_users
       WHERE email = LOWER($1)`,
      [email]
    );

    if (res.rows.length === 0) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const admin = res.rows[0];

    if (!admin.is_active) {
      return error('هذا الحساب غير نشط', 403);
    }

    const valid = await verifyPassword(password, admin.password_hash);
    if (!valid) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const sessionId = generateId();
    const code = String(Math.floor(100000 + Math.random() * 900000));

    createAdminSession(sessionId, admin.email, code);

    await sendTelegramCode(code);

    updateAdminSession(sessionId, { codeSent: true });

    const response = success({
      message: 'تم إرسال رمز التحقق إلى تيليجرام',
      email: admin.email,
    });

    response.cookies.set('admin_session', sessionId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 1800,
      path: '/',
    });

    return response;
  } catch (err) {
    return serverError(err);
  }
}

