import { Pool, PoolClient, QueryResult, QueryResultRow } from 'pg';

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 10000,
});

pool.on('error', (err) => {
  console.error('Unexpected pool error:', err);
});

export async function query<T extends QueryResultRow = any>(text: string, params?: any[]): Promise<QueryResult<T>> {
  const start = Date.now();
  try {
    const res = await pool.query<T>(text, params);
    const duration = Date.now() - start;
    if (duration > 1000) {
      console.warn('Slow query:', { text: text.substring(0, 100), duration, rows: res.rowCount });
    }
    return res;
  } catch (err) {
    console.error('Query error:', { text: text.substring(0, 100) });
    throw err;
  }
}

export async function transaction<T>(fn: (client: PoolClient) => Promise<T>): Promise<T> {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const result = await fn(client);
    await client.query('COMMIT');
    return result;
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();
  }
}

export async function getClient(): Promise<PoolClient> {
  return pool.connect();
}

export async function endPool(): Promise<void> {
  await pool.end();
}

import { NextRequest } from 'next/server';
import { success, error, unauthorized, serverError, parseBody } from '@/lib/api-helpers';
import { query } from '@/lib/db';
import { verifyPassword, createToken } from '@/lib/auth';
import { loginSchema } from '@/lib/validation';

export async function POST(request: NextRequest) {
  try {
    const body = await parseBody<{ email: string; password: string }>(request);
    const parsed = loginSchema.safeParse(body);
    if (!parsed.success) {
      return error(parsed.error.issues[0].message);
    }

    const { email, password } = parsed.data;

    const res = await query(
      `SELECT u.id, u.name, u.email, u.password, u.role, u.is_active, u.company_id,
              c.name as company_name, c.registration_number, c.tax_number,
              c.vat_number, c.address, c.phone, c.email as company_email,
              c.logo, c.is_active as company_active
       FROM users u
       JOIN companies c ON c.id = u.company_id
       WHERE u.email = LOWER($1)`,
      [email]
    );

    if (res.rows.length === 0) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const user = res.rows[0];

    if (!user.is_active) {
      return error('هذا الحساب غير نشط. تواصل مع مدير النظام', 403);
    }

    if (!user.company_active) {
      return error('الشركة غير نشطة. تواصل مع مدير النظام', 403);
    }

    const valid = await verifyPassword(password, user.password);
    if (!valid) {
      return error('البريد الإلكتروني أو كلمة المرور غير صحيحة', 401);
    }

    const token = createToken(user.id, user.role);

    await query(
      `UPDATE users SET last_login = NOW()::timestamp WHERE id = $1`,
      [user.id]
    );

    const { password: _, ...safeUser } = user;

    const response = success({
      user: safeUser,
      company: {
        id: user.company_id,
        name: user.company_name,
        registrationNumber: user.registration_number,
        taxNumber: user.tax_number,
        vatNumber: user.vat_number,
        address: user.address,
        phone: user.phone,
        email: user.company_email,
        logo: user.logo,
      },
      token,
    });

    response.cookies.set('token', token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: 86400 * 7,
      path: '/',
    });

    return response;
  } catch (err) {
    return serverError(err);
  }
}

