      );

      const itemsRes = await client.query(
        `SELECT id, description, quantity, unit_price, total FROM invoice_items WHERE invoice_id = $1`,
        [invoice.id]
      );

      return { ...invoice, items: itemsRes.rows, journalEntryId };
